const fs = require('fs');
const filePath = '/data/scenarios/scenarios.json';
const body = $input.first().json.body || $input.first().json;
const caseData = body.case || {};
const caseId = body.case_id || caseData.id || '';
const action = body.action || 'approve';

if (action !== 'approve') {
  return [{ json: { status: 'skipped', message: 'Non-approve action ignored' } }];
}

let db;
try { db = JSON.parse(fs.readFileSync(filePath, 'utf8')); }
catch(e) { db = { version: '1.0', last_updated: '', scenarios: [] }; }

// If already in catalog (generated by case-ingest), just confirm
const existing = db.scenarios.find(s => s.case_id === caseId);
if (existing) {
  return [{ json: { status: 'approved', scenario_id: existing.id, case_id: caseId, message: 'Scenario already in catalog' } }];
}

// Build minimal scenario from case data and publish
const tactics = caseData.mitre_tactics || [];
const techniques = (caseData.mitre_techniques || []).map(t => typeof t === 'string' ? {id:t, name:t} : t);
const id = 'SCN-APPR-' + Date.now().toString().slice(-6);

const scenario = {
  id: id,
  title: caseData.title || 'Approved Case Scenario',
  description: caseData.description || '',
  mitre_tactics: tactics,
  mitre_techniques: techniques,
  tools: caseData.tools || [],
  atomic_tests: [],
  caldera_ability: '',
  audience: 'Technical',
  platform: 'windows',
  execution_engine: 'atomic',
  expected_detections: [],
  talking_points: {
    universal: [
      'Based on a real-world ' + (caseData.source || 'incident') + ' case',
      'Threat actor: ' + (caseData.threat_actor || 'Unknown'),
      'Submitted by: ' + (caseData.submitted_by || 'MDR Team')
    ]
  },
  se_runbook: {
    setup: 'Original case source: ' + (caseData.source || 'Unknown') + '. Context: ' + (caseData.context || 'None'),
    steps: ['Review case details with customer', 'Configure target environment', 'Launch simulation and observe detections'],
    talking_points_timing: 'Introduce talking points after initial detection fires'
  },
  source: 'case-approved',
  case_id: caseId,
  submitted_by: caseData.submitted_by || '',
  industry: caseData.industry || 'universal'
};

db.scenarios.push(scenario);
db.last_updated = new Date().toISOString().split('T')[0];
fs.writeFileSync(filePath, JSON.stringify(db, null, 2), 'utf8');

return [{ json: { status: 'approved', scenario_id: id, case_id: caseId, message: 'Scenario published to catalog' } }];
